/*! Minimal Chart.js-compatible stub for offline prototypes */
(function (global) {
  function Chart(ctx, config) {
    this.ctx = ctx;
    this.canvas = ctx?.canvas;
    this.type = config.type || "bar";
    this.data = config.data || { labels: [], datasets: [] };
    this.options = config.options || {};
    this.render();
  }

  Chart.prototype.update = function () {
    this.render();
  };

  Chart.prototype.render = function () {
    if (!this.ctx || !this.canvas) return;
    if (this.type !== "bar") return;
    const { labels = [], datasets = [] } = this.data;
    const width = this.canvas.width;
    const height = this.canvas.height;

    this.ctx.clearRect(0, 0, width, height);
    this.ctx.font = "12px sans-serif";
    this.ctx.textBaseline = "bottom";

    const seriesCount = datasets.length;
    const valueMap = datasets.map((dataset) => dataset.data || []);
    const max = Math.max(
      ...valueMap.flat().map((value) => Number(value) || 0),
      1
    );

    const padding = 40;
    const chartWidth = width - padding * 2;
    const chartHeight = height - padding * 1.5;
    const barGroupWidth = chartWidth / (labels.length || 1);
    const barWidth = (barGroupWidth - 10) / Math.max(seriesCount, 1);

    labels.forEach((label, index) => {
      let x = padding + index * barGroupWidth + 5;
      datasets.forEach((dataset, seriesIndex) => {
        const value = Number(valueMap[seriesIndex][index] || 0);
        const barHeight = (value / max) * chartHeight;
        const barX = x + seriesIndex * barWidth;
        const barY = padding + chartHeight - barHeight;
        this.ctx.fillStyle = dataset.backgroundColor || "#5b56f6";
        this.ctx.beginPath();
        this.ctx.roundRect(barX, barY, barWidth, barHeight, 6);
        this.ctx.fill();
      });

      this.ctx.fillStyle = "#53627c";
      this.ctx.fillText(label, padding + index * barGroupWidth + 4, height - 6);
    });
  };

  if (typeof CanvasRenderingContext2D !== "undefined" && !CanvasRenderingContext2D.prototype.roundRect) {
    CanvasRenderingContext2D.prototype.roundRect = function (x, y, w, h, r) {
      const radius = typeof r === "number" ? { tl: r, tr: r, br: r, bl: r } : r;
      const defaultRadius = { tl: 0, tr: 0, br: 0, bl: 0 };
      for (const side in defaultRadius) {
        radius[side] = radius[side] || defaultRadius[side];
      }
      this.beginPath();
      this.moveTo(x + radius.tl, y);
      this.lineTo(x + w - radius.tr, y);
      this.quadraticCurveTo(x + w, y, x + w, y + radius.tr);
      this.lineTo(x + w, y + h - radius.br);
      this.quadraticCurveTo(x + w, y + h, x + w - radius.br, y + h);
      this.lineTo(x + radius.bl, y + h);
      this.quadraticCurveTo(x, y + h, x, y + h - radius.bl);
      this.lineTo(x, y + radius.tl);
      this.quadraticCurveTo(x, y, x + radius.tl, y);
      this.closePath();
      return this;
    };
  }

  global.Chart = Chart;
})(window);
